// ========== 拼写练习题（所有词） ==========
const makeSpelling = (words: { id: string; en: string; phonetic: string }[], startId: number): SpellingQuestion[] =>
  words.map((w, i) => ({ id: `sq${String(startId + i).padStart(3, '0')}`, wordId: w.id, en: w.en, phonetic: w.phonetic, audioText: w.en }));

